@@
+func TestRange_InclusiveBounds(t *testing.T) {
+	sl := New(42)
+	for _, k := range []string{"a", "b", "c", "d", "e"} {
+		sl.Insert(k, 1)
+	}
+
+	// lower bound matches an existing key and must be included
+	got := sl.Range("a", "c")
+	if len(got) != 3 || got[0].Key != "a" || got[2].Key != "c" {
+		t.Fatalf("expected [a b c], got %v", got)
+	}
+
+	// single-element inclusive range
+	single := sl.Range("c", "c")
+	if len(single) != 1 || single[0].Key != "c" {
+		t.Fatalf("expected [c], got %v", single)
+	}
+
+	// bounds between existing keys / empty result
+	empty := sl.Range("f", "z")
+	if len(empty) != 0 {
+		t.Fatalf("expected empty, got %v", empty)
+	}
+
+	// ascending order check
+	all := sl.Range("a", "e")
+	for i := 1; i < len(all); i++ {
+		if all[i-1].Key > all[i].Key {
+			t.Fatalf("not ascending: %v", all)
+		}
+	}
+}

