+package skiplist
+
+import "testing"
+
+func keysOf(entries []Entry) []string {
+	out := make([]string, 0, len(entries))
+	for _, e := range entries {
+		out = append(out, e.Key)
+	}
+	return out
+}
+
+func sortedAscending(ks []string) bool {
+	for i := 1; i < len(ks); i++ {
+		if ks[i-1] > ks[i] {
+			return false
+		}
+	}
+	return true
+}
+
+func TestRange_LowerBoundInclusive(t *testing.T) {
+	sl := New(42)
+	for _, k := range []string{"a", "b", "c", "d"} {
+		sl.Insert(k, 1)
+	}
+	ks := keysOf(sl.Range("a", "d"))
+	if len(ks) != 4 || ks[0] != "a" {
+		t.Fatalf("expected lower bound 'a' included, got %v", ks)
+	}
+	if !sortedAscending(ks) {
+		t.Fatalf("expected ascending order, got %v", ks)
+	}
+}
+
+func TestRange_UpperBoundInclusive(t *testing.T) {
+	sl := New(7)
+	for _, k := range []string{"a", "b", "c"} {
+		sl.Insert(k, 2)
+	}
+	ks := keysOf(sl.Range("a", "c"))
+	if len(ks) != 3 || ks[len(ks)-1] != "c" {
+		t.Fatalf("expected upper bound 'c' included, got %v", ks)
+	}
+}
+
+func TestRange_SingleElement(t *testing.T) {
+	sl := New(99)
+	sl.Insert("exact", 5)
+	ks := keysOf(sl.Range("exact", "exact"))
+	if len(ks) != 1 || ks[0] != "exact" {
+		t.Fatalf("expected single-element range to return 'exact', got %v", ks)
+	}
+}
+
+func TestRange_BetweenKeysAndEmpty(t *testing.T) {
+	sl := New(1)
+	for _, k := range []string{"a", "c", "e"} {
+		sl.Insert(k, 1)
+	}
+	ks := keysOf(sl.Range("b", "d"))
+	if len(ks) != 1 || ks[0] != "c" {
+		t.Fatalf("expected only 'c' between bounds, got %v", ks)
+	}
+	empty := keysOf(sl.Range("x", "z"))
+	if len(empty) != 0 {
+		t.Fatalf("expected empty result, got %v", empty)
+	}
+}

